params.text:
# LangGraph ST Agent Configuration
# ====================================

# RP LLM (Roleplay Model - KoboldCPP, Ollama, etc.)
RP_LLM_BASE_URL={{local.rp_config.rp_url || 'http://localhost:5001'}}
RP_LLM_API_KEY=none
RP_LLM_MODEL={{local.rp_config.rp_model || ''}}
RP_LLM_BACKEND={{local.rp_config.rp_backend || 'kobold'}}

# Logic LLM (Small model for state extraction)
LOGIC_LLM_BASE_URL={{local.logic_config.logic_url || 'http://localhost:11434'}}
LOGIC_LLM_API_KEY=none
LOGIC_LLM_MODEL={{local.logic_config.logic_model || 'llama3'}}
LOGIC_LLM_BACKEND={{local.logic_config.logic_backend || 'ollama'}}

# Database
# DB_DIR=./data

# Server
SERVER_PORT=8001

# Agent Behavior
CONTEXT_WINDOW_MESSAGES=20
DB_RETRIEVAL_COUNT=10
DEBUG_MODE=false
